import { Card } from "@/components/ui/card";
import { Wind, AlertCircle } from "lucide-react";
import type { AirQuality, HeatRiskLevel } from "@shared/schema";

interface AirQualityCardProps {
  airQuality: AirQuality;
  heatRiskLevel?: HeatRiskLevel;
}

const aqiLevelConfig = {
  good: {
    label: "Good",
    color: "text-green-600 dark:text-green-400",
    bgColor: "bg-green-100 dark:bg-green-900/30",
    borderColor: "border-green-200 dark:border-green-800",
  },
  moderate: {
    label: "Moderate",
    color: "text-yellow-600 dark:text-yellow-400",
    bgColor: "bg-yellow-100 dark:bg-yellow-900/30",
    borderColor: "border-yellow-200 dark:border-yellow-800",
  },
  unhealthy_sensitive: {
    label: "Unhealthy for Sensitive",
    color: "text-orange-600 dark:text-orange-400",
    bgColor: "bg-orange-100 dark:bg-orange-900/30",
    borderColor: "border-orange-200 dark:border-orange-800",
  },
  unhealthy: {
    label: "Unhealthy",
    color: "text-red-600 dark:text-red-400",
    bgColor: "bg-red-100 dark:bg-red-900/30",
    borderColor: "border-red-200 dark:border-red-800",
  },
  very_unhealthy: {
    label: "Very Unhealthy",
    color: "text-purple-600 dark:text-purple-400",
    bgColor: "bg-purple-100 dark:bg-purple-900/30",
    borderColor: "border-purple-200 dark:border-purple-800",
  },
  hazardous: {
    label: "Hazardous",
    color: "text-rose-600 dark:text-rose-400",
    bgColor: "bg-rose-100 dark:bg-rose-900/30",
    borderColor: "border-rose-200 dark:border-rose-800",
  },
};

function getCombinedHeatAqiWarning(heatRisk: HeatRiskLevel, aqiLevel: string): string | null {
  const isHighHeat = ["extreme_caution", "danger", "extreme_danger"].includes(heatRisk);
  const isPoorAir = ["unhealthy_sensitive", "unhealthy", "very_unhealthy", "hazardous"].includes(aqiLevel);

  if (isHighHeat && isPoorAir) {
    return "High heat combined with poor air quality creates heightened health risks. Limit outdoor activities and stay indoors in air-conditioned spaces.";
  }

  if (isHighHeat && aqiLevel === "moderate") {
    return "Heat stress can be amplified by moderate air quality. Sensitive individuals should take extra precautions.";
  }

  if (isPoorAir) {
    return "Poor air quality can increase heat-related health impacts. Stay hydrated and minimize outdoor exertion.";
  }

  return null;
}

export function AirQualityCard({ airQuality, heatRiskLevel }: AirQualityCardProps) {
  const config = aqiLevelConfig[airQuality.level];
  const combinedWarning = heatRiskLevel ? getCombinedHeatAqiWarning(heatRiskLevel, airQuality.level) : null;

  return (
    <Card className="p-6 md:p-8 rounded-xl" data-testid="card-air-quality">
      <div className="space-y-4">
        <div className="flex items-center gap-3">
          <Wind className="h-6 w-6 text-primary" data-testid="icon-air-quality" />
          <h2 className="text-lg md:text-xl font-semibold text-foreground" data-testid="heading-air-quality">
            Air Quality
          </h2>
        </div>

        <div className={`flex items-baseline gap-3 p-4 rounded-lg border ${config.bgColor} ${config.borderColor}`}>
          <div className="flex-1">
            <div className="flex items-baseline gap-2">
              <span className="text-4xl font-bold text-foreground" data-testid="text-aqi-value">
                {airQuality.aqi}
              </span>
              <span className="text-sm text-muted-foreground">AQI</span>
            </div>
            <div className={`text-sm font-semibold ${config.color}`} data-testid="text-aqi-level">
              {config.label}
            </div>
          </div>

          <div className="flex flex-col gap-2 text-right">
            <div className="text-sm">
              <span className="text-foreground font-medium" data-testid="text-pm25-value">{airQuality.pm25.toFixed(1)}</span>
              <span className="text-muted-foreground text-xs ml-1">PM2.5</span>
            </div>
            <div className="text-sm">
              <span className="text-foreground font-medium" data-testid="text-pm10-value">{airQuality.pm10.toFixed(1)}</span>
              <span className="text-muted-foreground text-xs ml-1">PM10</span>
            </div>
          </div>
        </div>

        {combinedWarning && (
          <div className="flex gap-3 p-4 rounded-lg bg-amber-50 dark:bg-amber-950/30 border border-amber-200 dark:border-amber-800" data-testid="alert-combined-warning">
            <AlertCircle className="h-5 w-5 text-amber-600 dark:text-amber-400 flex-shrink-0 mt-0.5" />
            <p className="text-sm text-foreground leading-relaxed">
              {combinedWarning}
            </p>
          </div>
        )}

        <div className="text-sm text-muted-foreground">
          <p>
            Air quality can significantly affect how heat impacts your health. Poor air quality makes it harder to breathe during heat exposure.
          </p>
        </div>
      </div>
    </Card>
  );
}

client/src/components/RiskTrendVisualiza.content:
import { format } from "date-fns";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { type DailyForecast, type HeatRiskLevel } from "@shared/schema";
import { TrendingUp, TrendingDown, Minus } from "lucide-react";

interface RiskTrendVisualizationProps {
  dailyForecasts: DailyForecast[];
}

const riskLevelValue: Record<HeatRiskLevel, number> = {
  normal: 1,
  caution: 2,
  extreme_caution: 3,
  danger: 4,
  extreme_danger: 5,
};

const riskLevelColor: Record<HeatRiskLevel, string> = {
  normal: "#22c55e",        // green-500
  caution: "#eab308",       // yellow-500
  extreme_caution: "#f97316", // orange-500
  danger: "#ef4444",        // red-500
  extreme_danger: "#7c3aed", // purple-600
};

const riskLevelLabel: Record<HeatRiskLevel, string> = {
  normal: "Normal",
  caution: "Caution",
  extreme_caution: "Extreme Caution",
  danger: "Danger",
  extreme_danger: "Extreme Danger",
};

export function RiskTrendVisualization({ dailyForecasts }: RiskTrendVisualizationProps) {
  if (!dailyForecasts || dailyForecasts.length === 0) {
    return null;
  }

  const maxRiskValue = 5;
  const chartHeight = 120;
  const chartWidth = 100; // percentage
  const padding = 8;

  // Calculate points for the line graph
  const points = dailyForecasts.map((forecast, index) => {
    const x = (index / (dailyForecasts.length - 1)) * 100;
    const riskValue = riskLevelValue[forecast.riskLevel];
    const y = chartHeight - ((riskValue - 1) / (maxRiskValue - 1)) * (chartHeight - padding * 2) - padding;
    return { x, y, risk: forecast.riskLevel, date: forecast.date };
  });

  // Create SVG path
  const pathD = points.map((point, index) => 
    `${index === 0 ? 'M' : 'L'} ${point.x} ${point.y}`
  ).join(' ');

  // Calculate overall trend
  const firstRisk = riskLevelValue[dailyForecasts[0].riskLevel];
  const lastRisk = riskLevelValue[dailyForecasts[dailyForecasts.length - 1].riskLevel];
  const trendDirection = lastRisk > firstRisk ? "increasing" : lastRisk < firstRisk ? "decreasing" : "stable";

  return (
    <Card data-testid="card-risk-trend">
      <CardHeader>
        <CardTitle className="flex items-center justify-between">
          <span>Heat Risk Trend</span>
          <div className="flex items-center gap-2 text-sm font-normal">
            {trendDirection === "increasing" && (
              <>
                <TrendingUp className="h-4 w-4 text-red-500" />
                <span className="text-red-500">Increasing Risk</span>
              </>
            )}
            {trendDirection === "decreasing" && (
              <>
                <TrendingDown className="h-4 w-4 text-green-500" />
                <span className="text-green-500">Decreasing Risk</span>
              </>
            )}
            {trendDirection === "stable" && (
              <>
                <Minus className="h-4 w-4 text-muted-foreground" />
                <span className="text-muted-foreground">Stable</span>
              </>
            )}
          </div>
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="relative" style={{ height: `${chartHeight}px` }}>
          <svg
            width="100%"
            height={chartHeight}
            viewBox={`0 0 100 ${chartHeight}`}
            preserveAspectRatio="none"
            className="overflow-visible"
            data-testid="svg-risk-trend"
          >
            {/* Background grid lines */}
            {[1, 2, 3, 4, 5].map((level) => {
              const y = chartHeight - ((level - 1) / (maxRiskValue - 1)) * (chartHeight - padding * 2) - padding;
              return (
                <line
                  key={level}
                  x1="0"
                  y1={y}
                  x2="100"
                  y2={y}
                  stroke="currentColor"
                  strokeWidth="0.5"
                  className="text-muted-foreground/20"
                />
              );
            })}

            {/* Gradient area under the line */}
            <defs>
              <linearGradient id="riskGradient" x1="0%" y1="0%" x2="0%" y2="100%">
                <stop offset="0%" stopColor={riskLevelColor[points[0].risk]} stopOpacity="0.3" />
                <stop offset="100%" stopColor={riskLevelColor[points[0].risk]} stopOpacity="0.05" />
              </linearGradient>
            </defs>

            {/* Area under the line */}
            <path
              d={`${pathD} L 100 ${chartHeight} L 0 ${chartHeight} Z`}
              fill="url(#riskGradient)"
            />

            {/* The main risk line */}
            <path
              d={pathD}
              fill="none"
              stroke={riskLevelColor[points[Math.floor(points.length / 2)].risk]}
              strokeWidth="2"
              strokeLinecap="round"
              strokeLinejoin="round"
            />

            {/* Data points */}
            {points.map((point, index) => (
              <circle
                key={index}
                cx={point.x}
                cy={point.y}
                r="3"
                fill={riskLevelColor[point.risk]}
                stroke="white"
                strokeWidth="1.5"
                className="hover:r-5 transition-all"
                data-testid={`point-risk-${point.date}`}
              />
            ))}
          </svg>

          {/* Day labels */}
          <div className="flex justify-between mt-2 text-xs text-muted-foreground">
            {dailyForecasts.map((forecast, index) => (
              <div
                key={forecast.date}
                className="flex-1 text-center"
                data-testid={`label-day-${forecast.date}`}
              >
                {index === 0 ? "Today" : format(new Date(forecast.date), "EEE")}
              </div>
            ))}
          </div>

          {/* Risk level legend */}
          <div className="flex flex-wrap gap-3 mt-4 text-xs">
            {Object.entries(riskLevelLabel).map(([level, label]) => (
              <div key={level} className="flex items-center gap-1.5">
                <div
                  className="w-3 h-3 rounded-full"
                  style={{ backgroundColor: riskLevelColor[level as HeatRiskLevel] }}
                />
                <span className="text-muted-foreground">{label}</span>
              </div>
            ))}
          </div>
        </div>
      </CardContent>
    </Card>
  );
}
